        self.limits = {'R1': (0, 100), 'R2': (0, 200), 'R3': (0, 50)}
        self.compounds = ['C', 'D', 'E']
        self.matrix = {
            ('C', 'R1'): -1, ('D', 'R1'): 1,
            ('C', 'R2'): 2, ('E', 'R2'): -1,
            ('D', 'R3'): -1, ('E', 'R3'): 1
        }
